    const hidden = [...pool].sort(() => Math.random() - 0.5).slice(0, seqLen);

    let dead = false;
    let localMistakes = 0;
    let currentStep = 0;
    let phase = 'PREVIEW';

    const field = el('div', 'fr-field'); body.appendChild(field);

    const msgWrap = el('div', 'fr-msg'); field.appendChild(msgWrap);

